const level = parseInt(query) || 1;
const db = {
  1: [
    { name: 'Goblin',   hp: 20, damage: '5-10',  xp: 10 },
    { name: 'Skeleton', hp: 30, damage: '10-15', xp: 20 },
    { name: 'Orc',      hp: 50, damage: '15-25', xp: 40 }
  ],
  2: [
    { name: 'Troll',     hp: 45, damage: '12-20', xp: 35 },
    { name: 'Dark Mage', hp: 35, damage: '18-28', xp: 45 },
    { name: 'Lich',      hp: 70, damage: '20-35', xp: 70 }
  ],
  3: [
    { name: 'Vampire', hp: 55,  damage: '20-30', xp: 60  },
    { name: 'Wyvern',  hp: 65,  damage: '22-32', xp: 70  },
    { name: 'Dragon',  hp: 100, damage: '25-45', xp: 120 }
  ]
};
return JSON.stringify({ level, monsters: db[level] || db[1] });

const monster = (query || '').toLowerCase().trim();
const tables = {
  'goblin':    [{ item: 'Gold', amount: 10, chance: 0.9 }, { item: 'Dagger',          chance: 0.2  }],
  'skeleton':  [{ item: 'Gold', amount: 15, chance: 0.8 }, { item: 'Shield',          chance: 0.25 }],
  'orc':       [{ item: 'Gold', amount: 25, chance: 0.9 }, { item: 'Sword',           chance: 0.3  }],
  'troll':     [{ item: 'Gold', amount: 20, chance: 0.8 }, { item: 'Potion',          chance: 0.4  }],
  'dark mage': [{ item: 'Gold', amount: 30, chance: 0.7 }, { item: 'Scroll',          chance: 0.35 }],
  'lich':      [{ item: 'Gold', amount: 50, chance: 1.0 }, { item: 'Magic Staff',     chance: 0.4  }],
  'vampire':   [{ item: 'Gold', amount: 40, chance: 0.9 }, { item: 'Ring of Shadows', chance: 0.3  }],
  'wyvern':    [{ item: 'Gold', amount: 45, chance: 0.9 }, { item: 'Scale Armor',     chance: 0.25 }],
  'dragon':    [{ item: 'Gold', amount: 100, chance: 1.0 }, { item: 'Legendary Sword', chance: 1.0  }]
};
const table = tables[monster] || [{ item: 'Gold', amount: 5, chance: 0.5 }];
const drops = [];
for (const row of table) {
  if (Math.random() <= row.chance) {
    drops.push(row.amount ? `${row.item} x${row.amount}` : row.item);
  }
}
return JSON.stringify({ monster, drops: drops.length ? drops : ['Nothing'] });
